/**
 * 后台管理 API 服务
 */
import { ApiService } from './api.service';

const apiService = ApiService.getInstance();

export interface PageResult<T> {
  records: T[];
  total: number;
  size: number;
  current: number;
}

export interface DashboardOverview {
  totalUsers: number;
  todayNewUsers: number;
  activeUsers: number;
  onlineUsers: number;
  totalGames: number;
  publishedGames: number;
  totalQuestions: number;
  totalAnswers: number;
  todayAnswers: number;
  answerCorrectRate: number;
  totalGameDuration: number;
  todayGameDuration: number;
}

export interface TodayStats {
  date: string;
  newUsers: number;
  activeUsers: number;
  gameCount: number;
  gameDuration: number;
  answerCount: number;
  correctAnswers: number;
  hourlyActiveUsers: Array<{
    hour: number;
    value: number;
  }>;
}

export interface TrendStats {
  days: number;
  dates: string[];
  newUsers: number[];
  activeUsers: number[];
  gameCounts: number[];
  answerCounts: number[];
  gameCategories: Array<{
    name: string;
    value: number;
  }>;
  answerCorrectRate: {
    correct: number;
    incorrect: number;
  };
}

export interface User {
  userId: number;
  username: string;
  nickname: string;
  avatar?: string;
  userType: number;
  status: number;
  fatiguePoints?: number;
  dailyAnswerPoints?: number;
  createTime: number;
  updateTime: number;
}

export interface Game {
  gameId: number;
  gameCode: string;
  gameName: string;
  category?: string;
  grade?: string;
  iconUrl?: string;
  coverUrl?: string;
  resourceUrl?: string;
  description?: string;
  modulePath?: string;
  sortOrder?: number;
  consumePointsPerMinute?: number;
  onlineCount?: number;
  status: number;
  createTime: number;
  updateTime: number;
}

export interface GameCreateParams {
  gameCode?: string;
  gameName: string;
  category: string;
  grade: string;
  iconUrl?: string;
  coverUrl?: string;
  resourceUrl?: string;
  description?: string;
  modulePath?: string;
  sortOrder?: number;
  consumePointsPerMinute?: number;
  status?: number;
}

export interface GameUpdateParams extends Partial<GameCreateParams> {}

export interface GameStats {
  gameId: number;
  totalPlayCount: number;
  todayPlayCount: number;
  averageScore?: number;
  favoriteCount?: number;
  satisfactionRate?: number;
}

export interface Question {
  questionId: number;
  content: string;
  options: string;
  correctAnswer: string;
  analysis?: string;
  grade: string;
  type: string;
  difficulty: number;
  status: number;
  createTime: number;
  updateTime: number;
}

export interface QuestionCreateDTO {
  content: string;
  options: string;
  correctAnswer: string;
  analysis?: string;
  grade: string;
  type?: string;
  difficulty?: number;
  status?: number;
}

export interface QuestionUpdateDTO {
  content?: string;
  options?: string;
  correctAnswer?: string;
  analysis?: string;
  grade?: string;
  type?: string;
  difficulty?: number;
  status?: number;
}

class AdminApiService {
  /**
   * 通用 GET 请求
   */
  private async get<T>(url: string, params?: any): Promise<{ data: T }> {
    const queryString = params ? '?' + new URLSearchParams(params).toString() : '';
    const result: any = await (apiService as any).request(`${url}${queryString}`);
    return { data: result.data };
  }

  /**
   * 通用 POST 请求
   */
  private async post<T>(url: string, data?: any): Promise<{ data: T }> {
    const result: any = await (apiService as any).request(url, {
      method: 'POST',
      body: JSON.stringify(data),
    });
    return { data: result.data };
  }

  /**
   * 通用 PUT 请求
   */
  private async put<T>(url: string, data?: any, params?: any): Promise<{ data: T }> {
    const queryString = params ? '?' + new URLSearchParams(params).toString() : '';
    const result: any = await (apiService as any).request(`${url}${queryString}`, {
      method: 'PUT',
      body: JSON.stringify(data),
    });
    return { data: result.data };
  }

  /**
   * 通用 DELETE 请求
   */
  private async delete<T>(url: string): Promise<{ data: T }> {
    const result: any = await (apiService as any).request(url, {
      method: 'DELETE',
    });
    return { data: result.data };
  }

  /**
   * 获取仪表盘概览
   */
  async getDashboardOverview(): Promise<DashboardOverview> {
    const response = await this.get<DashboardOverview>('/api/admin/dashboard/overview');
    return response.data;
  }

  /**
   * 获取今日实时统计
   */
  async getTodayStats(): Promise<TodayStats> {
    const response = await this.get<TodayStats>('/api/admin/dashboard/today-stats');
    return response.data;
  }

  /**
   * 获取趋势统计
   */
  async getTrendStats(days: number = 7): Promise<TrendStats> {
    const response = await this.get<TrendStats>(`/api/admin/dashboard/trend?days=${days}`);
    return response.data;
  }

  /**
   * 获取用户列表
   */
  async getUserList(params: {
    username?: string;
    userType?: number;
    status?: number;
    page?: number;
    size?: number;
  }): Promise<PageResult<User>> {
    const response = await this.get<PageResult<User>>('/api/admin/users', params);
    return response.data;
  }

  /**
   * 更新用户状态
   */
  async updateUserStatus(userId: number, status: number): Promise<void> {
    await this.put<void>(`/api/admin/users/${userId}/status`, null, { params: { status } });
  }

  /**
   * 获取游戏列表
   */
  async getGameList(params: {
    gameName?: string;
    category?: string;
    status?: number;
    page?: number;
    size?: number;
  }): Promise<PageResult<Game>> {
    const response = await this.get<PageResult<Game>>('/api/admin/games', params);
    return response.data;
  }

  /**
   * 更新游戏状态
   */
  async updateGameStatus(gameId: number, status: number): Promise<void> {
    await this.put<void>(`/api/admin/games/${gameId}/status`, null, { params: { status } });
  }

  /**
   * 获取题目列表
   */
  async getQuestionList(params: {
    content?: string;
    type?: string;
    difficulty?: number;
    status?: number;
    page?: number;
    size?: number;
  }): Promise<PageResult<Question>> {
    const response = await this.get<PageResult<Question>>('/api/admin/questions', params);
    return response.data;
  }

  /**
   * 创建题目
   */
  async createQuestion(data: QuestionCreateDTO): Promise<number> {
    const response = await this.post<number>('/api/admin/questions', data);
    return response.data;
  }

  /**
   * 更新题目
   */
  async updateQuestion(questionId: number, data: QuestionUpdateDTO): Promise<void> {
    await this.put<void>(`/api/admin/questions/${questionId}`, data);
  }

  /**
   * 删除题目
   */
  async deleteQuestion(questionId: number): Promise<void> {
    await this.delete<void>(`/api/admin/questions/${questionId}`);
  }

  /**
   * 获取最新注册用户
   */
  async getLatestUsers(limit: number = 5): Promise<User[]> {
    const response = await this.get<User[]>('/api/admin/users/latest', { limit });
    return response.data;
  }

  /**
   * 获取最新游戏记录
   */
  async getLatestGameRecords(limit: number = 5): Promise<Array<{ [key: string]: any }>> {
    const response = await this.get<Array<{ [key: string]: any }>>('/api/admin/game-records/latest', { limit });
    return response.data;
  }

  /**
   * 获取最新答题记录
   */
  async getLatestAnswerRecords(limit: number = 5): Promise<Array<{ [key: string]: any }>> {
    const response = await this.get<Array<{ [key: string]: any }>>('/api/admin/answer-records/latest', { limit });
    return response.data;
  }

  /**
   * 创建游戏
   */
  async createGame(params: GameCreateParams): Promise<Game> {
    const response = await this.post<Game>('/api/admin/games', params);
    return response.data;
  }

  /**
   * 更新游戏
   */
  async updateGame(gameId: number, params: GameUpdateParams): Promise<void> {
    await this.put<void>(`/api/admin/games/${gameId}`, params);
  }

  /**
   * 批量删除游戏
   */
  async batchDeleteGames(gameIds: number[]): Promise<void> {
    // 注意：DELETE 请求带 body 需要特殊处理
    const result: any = await (apiService as any).request('/api/admin/games/batch', {
      method: 'DELETE',
      body: JSON.stringify(gameIds),
    });
    return result.data;
  }

  /**
   * 获取游戏统计
   */
  async getGameStats(gameId: number): Promise<GameStats> {
    const response = await this.get<GameStats>(`/api/admin/games/${gameId}/stats`);
    return response.data;
  }
}

export const adminApi = new AdminApiService();
